mapper.insert:
insert into ck(
	ck_id, ck_date, ck_winner, ck_memo, ck_created_by
) values(
 #{ckId}, #{ckDate}, #{ckWinner}, #{ckMemo}, #{ckCreatedBy}
)

insert into ck_participant(
	ck_participant_id, ck_id, ck_streamer, ck_side, ck_position
) values(
	ck_participant_seq.nextval,
	#{ckId}, #{ckStreamer}, #{ckSide}, #{ckPosition}
)

mapper.select:
select * from ck_list
where ck_id in (
	select ck_id from ck_list where ck_streamer = #{streamerNo}
)
order by ck_date desc, ck_id desc, ck_side desc;
